"use strict";
class ConwayClient { constructor(options = {}) { this.baseUrl = String(options.baseUrl || options.url || "").replace(/\/+$/, ""); this.apiKey = options.apiKey || options.token || null; this.fetch = options.fetch || globalThis.fetch; } headers(extra = {}) { return { ...(this.apiKey ? { authorization: `Bearer ${this.apiKey}` } : {}), "content-type": "application/json", ...extra }; } async request(path, options = {}) { if (!this.fetch) throw new Error("fetch is not available"); const url = /^https?:/i.test(path) ? path : `${this.baseUrl}${path.startsWith("/") ? "" : "/"}${path}`; const response = await this.fetch(url, { ...options, headers: this.headers(options.headers) }); if (!response.ok) throw new Error(`Conway request failed ${response.status}: ${url}`); const text = await response.text(); return text ? JSON.parse(text) : null; } listProjects() { return this.request("/projects"); } getProject(id) { return this.request(`/projects/${encodeURIComponent(id)}`); } createSession(input = {}) { return this.request("/sessions", { method: "POST", body: JSON.stringify(input) }); } sendMessage(sessionId, message) { return this.request(`/sessions/${encodeURIComponent(sessionId)}/messages`, { method: "POST", body: JSON.stringify({ message }) }); } closeSession(sessionId) { return this.request(`/sessions/${encodeURIComponent(sessionId)}`, { method: "DELETE" }); } }
